### Complete Next.js Middleware for PostHog Flag Bootstrapping

Source: https://github.com/posthog/posthog.com/blob/master/contents/tutorials/nextjs-bootstrap-flags.md

A comprehensive Next.js middleware implementation that retrieves the distinct ID, fetches feature flags from PostHog, formats them for bootstrapping, and sets them as a cookie named 'bootstrapData' for client-side use.

```javascript
import { NextResponse } from 'next/server'

export async function middleware(request) {

  const ph_project_api_key = '<ph_project_api_key>'
  const ph_cookie_key = `ph_${ph_project_api_key}_posthog`
  const cookie = request.cookies.get(ph_cookie_key);

  let distinct_id;
  if (cookie) {
    distinct_id = JSON.parse(cookie.value).distinct_id;
  } else {
    distinct_id= crypto.randomUUID();
  }

  const requestOptions = {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      api_key: ph_project_api_key,
      distinct_id: distinct_id
    })
  };

  const ph_request = await fetch(
		'<ph_client_api_host>/flags?v=2', // or eu
		requestOptions
	);
  const data = await ph_request.json();

  const bootstrapData = {
    distinctID: distinct_id,
    featureFlags: data.featureFlags
  }

  const response = NextResponse.next()
  response.cookies.set('bootstrapData', JSON.stringify(bootstrapData))

  return response
}

export const config = {
  matcher: ['/((?!api|_next/static|favicon.ico|vercel.svg|next.svg).*)'],
};
```

