### Next.js Index Page for Blog Posts (JavaScript)

Source: https://github.com/posthog/posthog.com/blob/master/contents/tutorials/nextjs-pages-analytics.md

Creates the main index page for the blog in a Next.js application. It uses `getStaticProps` to fetch all blog posts from a static JSON file and renders them as a list of links. Each link points to the dynamic route for the individual post.

```javascript
// pages/index.js
import Head from 'next/head'
import Link from 'next/link'

export default function Home({ posts }) {
  return (
    <>
      <Head>
        <title>My blog</title>
      </Head>
      <main>
        <h1>Welcome to my blog</h1>
        <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <Link href={`/posts/${post.id}`}>
              <p>{post.title}</p>
            </Link>
          </li>
        ))}
        </ul>
      </main>
    </>
  )
}

export async function getStaticProps() {
  const { posts } = await import('../blog.json')
  return {
    props: {
      posts,
    },
  }
}
```

