### Fetch PostHog Bootstrap Data - JavaScript

Source: https://github.com/posthog/posthog.com/blob/master/contents/tutorials/nextjs-ab-tests.md

Fetches PostHog feature flags and the user's distinct ID on the server-side. It checks cookies for an existing ID, generates one if absent using `generateId`, and then uses `posthog-node` to retrieve all flags for the user.

```javascript
// app/utils/getBootstrapData.js
import { PostHog } from 'posthog-node'
import { cookies } from 'next/headers'
import { generateId } from './genId'

export async function getBootstrapData() {
  let distinct_id = ''
  const phProjectAPIKey = '<ph_project_api_key>'
  const phCookieName = `ph_${phProjectAPIKey}_posthog`
  const cookieStore = cookies()
  const phCookie = cookieStore.get(phCookieName)

  if (phCookie) {
    const phCookieParsed = JSON.parse(phCookie.value);
    distinct_id = phCookieParsed.distinct_id;
  }
  if (!distinct_id) {
    distinct_id = generateId()
  }

  const client = new PostHog(
    phProjectAPIKey,
    { host: "<ph_client_api_host>" })
  const flags = await client.getAllFlags(distinct_id)
  const bootstrap = {
    distinctID: distinct_id,
    featureFlags: flags
  }

  return bootstrap
}
```

