### Next.js Middleware for PostHog Proxy

Source: https://github.com/posthog/posthog.com/blob/master/contents/docs/advanced/proxy/nextjs-middleware.mdx

This JavaScript code configures Next.js middleware to proxy requests to PostHog. It dynamically sets the PostHog host based on the request path and rewrites the URL. Ensure you replace `<ph_proxy_path>` with your actual proxy path.

```javascript
import { NextResponse } from 'next/server'

export function middleware(request) {
  let url = request.nextUrl.clone()
  const hostname = url.pathname.startsWith("/<ph_proxy_path>/static/") ? 'us-assets.i.posthog.com' : 'us.i.posthog.com'
  const requestHeaders = new Headers(request.headers)

  requestHeaders.set('host', hostname)

  url.protocol = 'https'
  url.hostname = hostname
  url.port = 443
  url.pathname = url.pathname.replace("/^/<ph_proxy_path>/", '');

  return NextResponse.rewrite(url, {
    headers: requestHeaders,
  })
}

export const config = {
  matcher: '/<ph_proxy_path>/:path*',
}
```

